import{_ as t,o as e,c as r,a6 as i,eQ as o,eR as s,eS as l,eT as p,eU as c,eV as n,eW as m,eX as h,eY as d,eZ as k,e_ as _,e$ as b,f0 as g,f1 as f,f2 as u,f3 as S,f4 as x,f5 as P,f6 as M,f7 as K,f8 as D,f9 as W,fa as U,fb as v,fc as w,fd as I,fe as R}from"./chunks/framework.UYVGz2W_.js";const V=JSON.parse('{"title":"チャットの統合","description":"","frontmatter":{},"headers":[],"relativePath":"ja/chat-integration/index.md","filePath":"ja/chat-integration/index.md"}'),A={name:"ja/chat-integration/index.md"};function B(L,a,T,q,E,C){return e(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="チャットの統合" tabindex="-1">チャットの統合 <a class="header-anchor" href="#チャットの統合" aria-label="Permalink to “チャットの統合”">​</a></h1><h2 id="discordの統合" tabindex="-1">Discordの統合 <a class="header-anchor" href="#discordの統合" aria-label="Permalink to “Discordの統合”">​</a></h2><h3 id="ボットアカウントの作成" tabindex="-1">ボットアカウントの作成 <a class="header-anchor" href="#ボットアカウントの作成" aria-label="Permalink to “ボットアカウントの作成”">​</a></h3><ol><li><a href="https://discord.com/" target="_blank" rel="noreferrer">Discordウェブサイト</a>にログインしていることを確認してください。</li><li><a href="https://discord.com/developers/applications" target="_blank" rel="noreferrer">アプリケーションページ</a>に移動します。</li><li>「新規アプリケーション」ボタンをクリックします。</li><li>アプリケーションに名前を付け（例：「Kitsu」）、「作成」をクリックします。</li></ol><p><img src="'+o+'" alt="アプリケーションの作成"></p><ol start="5"><li>「Bot」タブに移動し、「Add Bot」をクリックして、Botユーザーを作成します。 「Yes, do it!」をクリックして続行します。</li></ol><p><img src="'+s+'" alt="ボットの作成"></p><ol start="6"><li><p>「Username」の隣にあるアイコンをクリックすると、ボットのアイコンを追加できます。このアイコンはボットがチャットを行う際に使用されます。</p></li><li><p>他のユーザーにボットを招待してもらいたい場合は、「Public Bot」にチェックが入っていることを確認してください。</p></li></ol><p><img src="'+l+'" alt="Public Botにチェックが入っている"></p><ol start="8"><li>ボットが他のメンバーを確認できるようにするには、「Server Members Intent」にチェックが入っていることを確認してください。</li></ol><p><img src="'+p+'" alt="Server Members Intent ticked"></p><ol start="9"><li><p>「Copy」ボタンをクリックしてトークンをコピーします。</p></li><li><p>Kitsuの「設定」画面で、テキストフィールド「Discord token (optional)」にトークンを貼り付け、「Save settings」をクリックします。</p></li></ol><p><img src="'+c+'" alt="Add discord token to settings"></p><h3 id="ボットの招待" tabindex="-1">ボットの招待 <a class="header-anchor" href="#ボットの招待" aria-label="Permalink to “ボットの招待”">​</a></h3><p>ボットユーザーを作成したら、それをサーバーに追加する必要があります。以下の手順に従ってください。</p><ol><li><a href="https://discord.com/" target="_blank" rel="noreferrer">Discord ウェブサイト</a> にログインしていることを確認してください。</li><li><a href="https://discord.com/developers/applications" target="_blank" rel="noreferrer">アプリケーションページ</a> に移動します。</li><li>ボットのページをクリックします。</li><li>「OAuth2」タブから「URL Generator」に進みます。</li><li>「Scopes」で「bot」のみにチェックを入れます。</li></ol><p><img src="'+n+'" alt="URL Generator Scopes"></p><ol start="6"><li>「Bot Permissions」で「Send Messages」のみにチェックを入れます。</li></ol><p><img src="'+m+'" alt="URL Generator Bot permissions"></p><ol start="7"><li>生成されたURLを使用して、サーバーにボットを追加します。URLをブラウザにコピー＆ペーストし、ボットを招待するサーバーを選択して、「Authorize（認証）」をクリックします。</li></ol><blockquote><p><strong><em>注意：</em></strong> ボットを追加するには、そのユーザーに「Manage Server（サーバー管理）」権限が必要です。</p></blockquote><blockquote><p><strong><em>注意：</em></strong> 通知を有効にするには、ユーザーはボットと同じサーバー上にいる必要があります。</p></blockquote><h3 id="discord-通知を有効にする" tabindex="-1">Discord 通知を有効にする <a class="header-anchor" href="#discord-通知を有効にする" aria-label="Permalink to “Discord 通知を有効にする”">​</a></h3><p>各ユーザーは、プロフィールで Discord にプッシュ通知を設定できます。「Discord 通知を有効にする」を「はい」に切り替え、「Discord ユーザー名」（フォーマットは username#number）を入力する必要があります。</p><p><img src="'+h+'" alt="プロフィールに discord ユーザー名を追加"></p><p>完了です！</p><h2 id="slack-統合" tabindex="-1">Slack 統合 <a class="header-anchor" href="#slack-統合" aria-label="Permalink to “Slack 統合”">​</a></h2><p>Slack との連携には、Slack スペースに専用のアプリケーションを作成する必要があります。以下の手順で設定を進めてください。</p><h3 id="slack-に-kitsu-アプリケーションを作成" tabindex="-1">Slack に Kitsu アプリケーションを作成 <a class="header-anchor" href="#slack-に-kitsu-アプリケーションを作成" aria-label="Permalink to “Slack に Kitsu アプリケーションを作成”">​</a></h3><p>まず、<a href="https://api.slack.com/apps" target="_blank" rel="noreferrer">https://api.slack.com/apps</a> に接続します。</p><p>「新しいアプリを作成」ボタンをクリックします。</p><p><img src="'+d+'" alt="新しいアプリを作成"></p><p>名前に「Kitsu」と入力し、Kitsuインスタンスとリンクするワークスペースを選択します。</p><p><img src="'+k+'" alt="ワークスペースの選択"></p><p>適切な権限を設定する</p><p>アプリを作成したら、リストからアプリの名前をクリックしてアプリのページに移動します。「基本情報」セクションに移動し、右下の「権限」ボタンをクリックします。</p><p><img src="'+_+'" alt="権限ボタン"></p><p>スコープセクションで、必要な権限を追加します。</p><p><img src="'+b+'" alt="スコープの追加"></p><p>必要な権限のスコープは <code>chat:write:bot</code> です。</p><p><img src="'+g+'" alt="権限スコープ"></p><h3 id="ワークスペースにアプリをインストール" tabindex="-1">ワークスペースにアプリをインストール <a class="header-anchor" href="#ワークスペースにアプリをインストール" aria-label="Permalink to “ワークスペースにアプリをインストール”">​</a></h3><p>ワークスペースにアプリをインストールします。「アプリのインストール」セクションに移動し、「ワークスペースにアプリをインストール」ボタンをクリックしてインストールします。</p><p><img src="'+f+'" alt="アプリのインストール"></p><p>インストールを確認します。</p><p><img src="'+u+'" alt="インストール確認"></p><p>これで、Kitsu Slack アプリが稼働しました。あとは、Slack ワークスペースに送信される通知に Kitsu をリンクするだけです。</p><h3 id="トークンの取得" tabindex="-1">トークンの取得 <a class="header-anchor" href="#トークンの取得" aria-label="Permalink to “トークンの取得”">​</a></h3><p><em>アプリのインストール</em>セクションに戻ります。Kitsu インスタンスを Slack にリンクするために必要なトークンが表示されます。</p><p><img src="'+S+'" alt="トークンの取得"></p><h3 id="kitsuを新しいslackアプリケーションにリンク" tabindex="-1">Kitsuを新しいSlackアプリケーションにリンク <a class="header-anchor" href="#kitsuを新しいslackアプリケーションにリンク" aria-label="Permalink to “Kitsuを新しいSlackアプリケーションにリンク”">​</a></h3><p>有効なトークンを使って、Kitsuの設定ページに移動し、トークンを入力します。</p><p><img src="'+x+'" alt="設定にトークンを追加"></p><h3 id="プロフィールでslack通知を有効にする" tabindex="-1">プロフィールでSlack通知を有効にする <a class="header-anchor" href="#プロフィールでslack通知を有効にする" aria-label="Permalink to “プロフィールでSlack通知を有効にする”">​</a></h3><p>最後に、プロフィールセクションでSlack通知をオンにします。Slackのプロフィールで「その他」をクリックすると表示される、Slackで使用しているメンバーIDを入力します。</p><p><img src="'+P+'" alt="メンバーIDの確認"></p><p><img src="'+M+'" alt="メンバーID"></p><p>Kitsuのプロフィールで、Slack通知を「オン」に設定し、Slackのニックネームを入力します。</p><p><img src="'+K+'" alt="Slack通知の設定"></p><p>これで、Slackワークスペースで直接通知を受け取ることができます！</p><p><img src="'+D+'" alt="Slack通知"></p><h2 id="mattermost-統合" tabindex="-1">Mattermost 統合 <a class="header-anchor" href="#mattermost-統合" aria-label="Permalink to “Mattermost 統合”">​</a></h2><h3 id="受信-webhook、カスタムユーザー名、webhook-用プロフィール画像を有効にする" tabindex="-1">受信 Webhook、カスタムユーザー名、Webhook 用プロフィール画像を有効にする <a class="header-anchor" href="#受信-webhook、カスタムユーザー名、webhook-用プロフィール画像を有効にする" aria-label="Permalink to “受信 Webhook、カスタムユーザー名、Webhook 用プロフィール画像を有効にする”">​</a></h3><ol><li>Mattermost サーバーにシステム管理アカウントでログインしていることを確認してください。</li><li>Mattermost インストールで受信 Webhook を受信でき、Webhook 用にカスタムユーザー名とプロフィール画像を設定できるか確認してください。</li><li>「システムコンソール」 --&gt; 「統合」 --&gt; 「統合管理」に進みます。</li></ol><p><img src="'+W+'" alt="Integration management"></p><ol start="2"><li>パラメータ「Enable incoming Webhooks」、「Enable integrations to override usernames」、および「Enable integrations to override profile picture icons」が「true」に設定されていることを確認します。</li></ol><p><img src="'+U+'" alt="Enable incoming webhooks"></p><h3 id="mattermostでwebhookを設定する" tabindex="-1">MattermostでWebhookを設定する <a class="header-anchor" href="#mattermostでwebhookを設定する" aria-label="Permalink to “MattermostでWebhookを設定する”">​</a></h3><ol><li>Mattermostサーバーにシステム管理アカウントでログインしていることを確認してください。</li><li>「Integrations」 --&gt; 「Incoming Webhooks」 --&gt; 「Add incoming Webhook」の順にアクセスします。</li></ol><p><img src="'+v+'" alt="Add incoming webhook"></p><ol start="3"><li>受信Webhookを作成します。</li></ol><p><img src="'+w+'" alt="Create incoming webhook"></p><ul><li><strong>Title</strong>: Kitsu</li><li><strong>Description</strong>: Kitsu</li><li><strong>Channel</strong>: メッセージはユーザーに送信されるので、新しいチャンネルを作成するか、既存のチャンネルを使用します。</li><li><strong>Lock to this channel</strong>: False に設定します。</li><li><strong>Username</strong>: Kitsu (これは Kitsu によって上書きされます)。</li><li><strong>プロフィール画像</strong>: 重要ではありません。Kitsuによって上書きされます。</li></ul><ol start="4"><li><p>「保存」をクリックすると、Mattermostが新しいURLを生成します。このURLをコピーします。</p></li><li><p>Kitsuの「設定」で、テキストフィールド「Mattermost Webhooks (オプション)」にURLを貼り付け、「設定を保存」をクリックします。</p></li></ol><p><img src="'+I+'" alt="Mattermost ウェブフック設定の追加"></p><blockquote><p><strong><em>注意:</em></strong> 通知を有効にしたいユーザーは、これらの手順で使用したのと同じ Mattermost サーバー上に存在していなければなりません。</p></blockquote><h3 id="mattermost-通知を有効にする" tabindex="-1">Mattermost 通知を有効にする <a class="header-anchor" href="#mattermost-通知を有効にする" aria-label="Permalink to “Mattermost 通知を有効にする”">​</a></h3><p>各ユーザーは、プロフィールで Mattermost にプッシュ通知を行うように設定できます。「Mattermost 通知を有効にする」を「はい」に切り替え、「Mattermost ユーザー名」を入力する必要があります。</p><p><img src="'+R+'" alt="プロフィールに Mattermost ユーザー名を追加"></p><p>完了です！</p>',80)])])}const j=t(A,[["render",B]]);export{V as __pageData,j as default};
